## 1. Contracts List Page — `/home/aditya/projects/alpauls-ats/src/routes/(protected)/(app)/contracts/index.tsx`

Full source (55 lines):

```tsx
import { IconPlus, IconSearch } from "@tabler/icons-react";
import { useQuery } from "@tanstack/react-query";
import { createFileRoute } from "@tanstack/react-router";
import { useState } from "react";

import { ContractsTable } from "@/components/tables/contracts-table";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { rpc } from "@/rpc/client";

export const Route = createFileRoute("/(protected)/(app)/contracts/")({
  component: ContractsPage,
});

function ContractsPage() {
  const navigate = Route.useNavigate();
  const [search, setSearch] = useState("");

  const { data, isLoading } = useQuery(
    rpc.contract.list.queryOptions({ input: {} }),
  );

  return (
    <div className="space-y-6 p-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="font-semibold text-lg">Contracts</h2>
          <p className="text-muted-foreground text-sm">
            Manage client contracts and agreements
          </p>
        </div>
        <Button onClick={() => navigate({ to: "/contracts/new" })} size="sm">
          <IconPlus className="mr-1 h-4 w-4" />
          New Contract
        </Button>
      </div>

      <div className="relative max-w-sm">
        <IconSearch className="absolute top-2.5 left-2.5 h-4 w-4 text-muted-foreground" />
        <Input
          className="pl-8"
          onChange={(e) => setSearch(e.target.value)}
          placeholder="Search by title, reference, or client..."
          value={search}
        />
      </div>

      <ContractsTable
        contracts={data?.items ?? []}
        isLoading={isLoading}
        search={search}
      />
    </div>
  );
}
```

**Pattern summary for Contracts:**
- **Layout**: Simple `<div className="space-y-6 p-6">` — no wrapper layout component.
- **Header**: Manual flex row with `<h2>` title + `<p>` subtitle on the left, "New" `<Button>` on the right.
- **Search**: Client-side `useState` search, plain `<Input>` with search icon overlay, `max-w-sm`.
- **Data fetching**: `useQuery(rpc.contract.list.queryOptions({ input: {} }))` — no pagination params passed.
- **Table**: Delegates to `<ContractsTable>` component which uses shadcn `<Table>`/`<TableHeader>`/`<TableBody>`/`<TableRow>`/`<TableHead>`/`<TableCell>`.
- **Status badges**: Uses `<Badge variant="outline">` with custom `className` from a `STATUS_STYLES` map (e.g. `"bg-emerald-500/10 text-emerald-600 dark:text-emerald-400"` for active).
- **Row click**: `navigate({ to: "/contracts/$contractId", params: { contractId } })`.
- **Loading**: Renders 5 skeleton `<TableRow>`s with `<Skeleton>` placeholders.
- **Empty state**: Single `<TableRow>` with colSpan and muted text.

---

## 2. Clients List Page — `/home/aditya/projects/alpauls-ats/src/routes/(protected)/(app)/clients/index.tsx`

Full source (39 lines):

```tsx
import { createFileRoute, Link, useNavigate } from "@tanstack/react-router";
import { Plus } from "lucide-react";
import { z } from "zod";

import type { ClientItem } from "@/components/client-list-view";
import { ClientListView } from "@/components/client-list-view";
import NavLayout from "@/components/layouts/nav-layout";

export const Route = createFileRoute("/(protected)/(app)/clients/")({
  component: ClientsPage,
  validateSearch: z.object({}),
});

function ClientsPage() {
  const navigate = useNavigate();

  return (
    <NavLayout
      baseUrl="/clients"
      label="Clients"
      leftItems={<div>FILTER ITEMS</div>}
      rightItems={
        <Link className="flex" to="/clients/new">
          <Plus className="mr-1.5 h-4 w-4" />
          New Client
        </Link>
      }
    >
      <ClientListView
        onClientClick={(client: ClientItem) =>
          navigate({
            params: { clientId: String(client.id) },
            to: "/clients/$clientId",
          })
        }
      />
    </NavLayout>
  );
}
```

**Pattern summary for Clients:**
- **Layout**: Uses `<NavLayout>` wrapper component (breadcrumb-style header with `label > leftItems` on the left and `rightItems` on the right, followed by `children` in padded container).
- **Header**: Delegated to `NavLayout` — link to baseUrl + ChevronRight + leftItems slot. "New Client" as `<Link>` in `rightItems`.
- **Data fetching**: Done inside `<ClientListView>` using `useQuery(rpc.client.list.queryOptions(...))` with pagination (`cursor`, `limit: 20`) and server-side filter params.
- **Table**: Uses `@tanstack/react-table` (`useReactTable` + `getCoreRowModel` + `flexRender`) with shadcn `<Table>`, same wrapping pattern (`<div className="rounded-lg border bg-card">`).
- **Search/filters**: URL-synced via `nuqs` (`useQueryState("filters", ...)`). Uses a `DataTableFilter` component + column config helper. Search input + filter popover.
- **Pagination**: Cursor-based with a "Load more" `<Button variant="outline">` at the bottom.
- **Row click**: `onClientClick` callback navigates to `/clients/$clientId`.
- **Loading**: Single row with "Loading..." text (no skeletons).
- **Empty state**: Single row with "No clients found".

