## 3. Badge Component — `/home/aditya/projects/alpauls-ats/src/components/ui/badge.tsx`

Full source (52 lines):

```tsx
import { mergeProps } from "@base-ui/react/merge-props";
import { useRender } from "@base-ui/react/use-render";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils.ts";

const badgeVariants = cva(
  "group/badge inline-flex h-5 w-fit shrink-0 items-center justify-center gap-1 overflow-hidden whitespace-nowrap rounded-4xl border border-transparent px-2 py-0.5 font-medium text-xs transition-all focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 has-data-[icon=inline-end]:pr-1.5 has-data-[icon=inline-start]:pl-1.5 aria-invalid:border-destructive aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 [&>svg]:pointer-events-none [&>svg]:size-3!",
  {
    defaultVariants: {
      variant: "default",
    },
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground [a]:hover:bg-primary/80",
        destructive:
          "bg-destructive/10 text-destructive focus-visible:ring-destructive/20 dark:bg-destructive/20 dark:focus-visible:ring-destructive/40 [a]:hover:bg-destructive/20",
        ghost:
          "hover:bg-muted hover:text-muted-foreground dark:hover:bg-muted/50",
        link: "text-primary underline-offset-4 hover:underline",
        outline:
          "border-border text-foreground [a]:hover:bg-muted [a]:hover:text-muted-foreground",
        secondary:
          "bg-secondary text-secondary-foreground [a]:hover:bg-secondary/80",
      },
    },
  },
);

function Badge({
  className,
  variant = "default",
  render,
  ...props
}: useRender.ComponentProps<"span"> & VariantProps<typeof badgeVariants>) {
  return useRender({
    defaultTagName: "span",
    props: mergeProps<"span">(
      {
        className: cn(badgeVariants({ variant }), className),
      },
      props,
    ),
    render,
    state: {
      slot: "badge",
      variant,
    },
  });
}

export { Badge, badgeVariants };
```

**Badge pattern summary:**
- Built on `@base-ui/react` (`useRender` + `mergeProps`) with `cva` for variant styling.
- Variants: `default`, `destructive`, `ghost`, `link`, `outline`, `secondary`.
- For entity type badges (like contract status), the contracts table uses `<Badge variant="outline">` with a custom `className` override for color (e.g., `"bg-emerald-500/10 text-emerald-600 dark:text-emerald-400"` for active, `"bg-slate-500/10 text-slate-600 dark:text-slate-400"` for inactive).
- The badge is a pill shape (`rounded-4xl`), fixed height `h-5`, with `text-xs` font-medium text.

---

## Key Differences Between the Two List Pages

| Aspect | Contracts | Clients |
|---|---|---|
| **Layout wrapper** | Plain `<div className="space-y-6 p-6">` | `<NavLayout>` (breadcrumb bar + padded content) |
| **Data fetching location** | Route component (`useQuery` in page) | Inside `<ClientListView>` component |
| **Search** | Client-side `useState` filtering | URL-synced via `nuqs` + `DataTableFilter` |
| **Table implementation** | Direct JSX in `<ContractsTable>` | `@tanstack/react-table` with column defs |
| **Pagination** | None (loads all) | Cursor-based ("Load more" button) |
| **Loading skeleton** | 5 skeleton rows with `<Skeleton>` components | Single "Loading..." text row |
| **Status display** | `<Badge variant="outline">` with custom color class | Archive icon inside name column |
| **"New" button** | `<Button>` with `IconPlus` | `<Link>` with `Plus` icon |
